#include <iostream>
#include <string>

class Car {
public:
    std::string brand;
    std::string model;

    void drive() {
        std::cout << "The " << brand << " " << model << " is driving!" << std::endl;
    }
};

int main() {
    Car myCar;
    myCar.brand = "Tesla";
    myCar.model = "Model S";
    myCar.drive();
    return 0;
}
